554	        state.check_arg_type(1, LuaType::Table)?;
555	        // C: lua_settop(L, 1);  /* make sure table is at the top */
556	        // PORT NOTE: must use the public-API `set_top` (relative to the current
557	        // C-frame's `func`), not `LuaState::set_top` which is an inherent that
558	        // sets an absolute stack index and would truncate the entire stack.
559	        lua_vm::api::set_top(state, 1)?;
560	
561	        // C: ts.tm_year = getfield(L, "year",  -1, 1900);
562	        let tm_year  = get_field(state, b"year",  -1, 1900)?;
563	        // C: ts.tm_mon  = getfield(L, "month", -1, 1);
564	        let tm_mon   = get_field(state, b"month", -1, 1)?;
565	        // C: ts.tm_mday = getfield(L, "day",   -1, 0);
566	        let tm_mday  = get_field(state, b"day",   -1, 0)?;
567	        // C: ts.tm_hour = getfield(L, "hour",  12, 0);
