573	        // C: ts.tm_isdst = getboolfield(L, "isdst");
574	        let tm_isdst = get_bool_field(state, b"isdst")?;
575	
576	        let stm = TmFields {
577	            tm_year,
578	            tm_mon,
579	            tm_mday,
580	            tm_hour,
581	            tm_min,
582	            tm_sec,
583	            tm_isdst,
584	            ..TmFields::default()
585	        };
586	
587	        // C: t = mktime(&ts);
588	        // TODO(port): call `libc::mktime` to normalise stm fields and compute the
589	        // Unix timestamp.  Phase A stub uses 0 and skips normalisation.
590	        t = 0;
591	
592	        // C: setallfields(L, &ts);  /* update fields with normalized values */
593	        // PORT NOTE: In the real implementation, mktime may alter stm (e.g.
594	        // normalise out-of-range values), so we update the table with the
595	        // post-normalisation stm.  Phase A stm is unmodified.
596	        set_all_fields(state, &stm)?;
597	    }
