217	///                                     ptrdiff_t convlen, char *buff)`
218	///
219	/// Validates the `strftime` conversion specifier at the start of `conv` against
220	/// `STRFTIME_OPTIONS`.
221	///
222	/// `cc` must have `cc[0] == b'%'` on entry (set by the caller).  On success the
223	/// matched specifier bytes are written into `cc[1..=oplen]`, a null terminator is
224	/// written at `cc[oplen+1]`, and the sub-slice of `conv` after the consumed
225	/// specifier is returned.
226	///
227	/// On failure a `LuaError::arg_error` describing the invalid specifier is
228	/// returned.
229	///
230	/// The options table uses `|` characters as length-transition markers: one `|`
231	/// increments `oplen` from 1 to 2 (and the following advance jumps past the `||`
232	/// sentinel), enabling 2-char specifiers like `%EC`.
233	fn check_strftime_option<'a>(
234	    state: &mut LuaState,
235	    conv: &'a [u8],
236	    cc: &mut [u8; 4],
237	) -> Result<&'a [u8], LuaError> {
238	    let options = STRFTIME_OPTIONS;
239	    let mut oplen: usize = 1;
240	    let mut i: usize = 0;
241	
242	    // C: for (; *option != '\0' && oplen <= convlen; option += oplen)
243	    while i < options.len() && oplen <= conv.len() {
244	        if options[i] == b'|' {
245	            // C: if (*option == '|') oplen++;  then option advances by new oplen
246	            // Increment first so the subsequent `i += oplen` uses the new value,
247	            // which jumps from the first `|` past the entire `||` separator block.
248	            oplen += 1;
249	            i += oplen;
250	        } else if i + oplen <= options.len() && conv[..oplen] == options[i..i + oplen] {
251	            // C: memcpy(buff, conv, oplen); buff[oplen] = '\0';
252	            // cc[0] = b'%' is pre-filled; write specifier bytes into cc[1..=oplen].
253	            debug_assert!(oplen <= 2, "STRFTIME_OPTIONS only has 1- and 2-char specifiers");
254	            cc[1..=oplen].copy_from_slice(&conv[..oplen]);
255	            cc[oplen + 1] = 0;
256	            // C: return conv + oplen;
257	            return Ok(&conv[oplen..]);
258	        } else {
259	            // C: option += oplen  (advance to the next entry in the options list)
260	            i += oplen;
261	        }
262	    }
263	    // C: luaL_argerror(L, 1, lua_pushfstring(L, "invalid conversion specifier '%%%s'", conv));
264	    Err(LuaError::arg_error(
265	        1,
266	        "invalid conversion specifier",
267	    ))
268	}
